concepts.explanation:
input  [63:0] data1, data2,
input  [1:0]  ALUop,
output reg    iszero,
output reg [63:0] result);

always @ begin
if (data2 == 0)
iszero = 1;
else iszero = 0;
case (ALUop)
2'b00: result = data1 + data2;
2'b01: result = data1 - data2;
2'b10: result = data1 & data2;
2'b11: result = data1 | data2;
endcase
end
endmodule

